import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;

import okhttp3.OkHttpClient;
import okhttp3.TlsVersion;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class MainActivity extends AppCompatActivity {

    private static final String API_URL = "https://api.example.com";
    private static final String DEVELOPMENT_API_URL = "https://dev-api.example.com";
    private static final String STAGING_API_URL = "https://stg-api.example.com";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        Retrofit retrofit;
        switch (BuildConfig.BUILD_TYPE) {
            case "debug":
                retrofit = getRetrofit(DEVELOPMENT_API_URL, false);
                break;
            case "staging":
                retrofit = getRetrofit(STAGING_API_URL, true);
                break;
            default:
                retrofit = getRetrofit(API_URL, true);
        }

        UserApi userApi = retrofit.create(UserApi.class);
        Call<User> call = userApi.getUser(1);
        call.enqueue(new Callback<User>() {
            @Override
            public void onResponse(Call<User> call, Response<User> response) {
                if (response.isSuccessful()) {
                    Log.d("User", response.body().toString());
                } else {
                    Log.e("Error", "Failed to fetch user data");
                }
            }

            @Override
            public void onFailure(Call<User> call, Throwable t) {
                Log.e("Error", "Failed to fetch user data");
            }
        });
    }

    private Retrofit getRetrofit(String apiUrl, boolean pinningRequired) {
        OkHttpClient client = new OkHttpClient.Builder()
                .tlsVersion(TlsVersion.TLS_1_2)
                .build();

        if (pinningRequired) {
            client = client.newBuilder()
                    .hostnameVerifier(new HostnameVerifier() {
                        @Override
                        public boolean verify(String hostname, SSLSession session) {
                            return true;
                        }
                    })
                    .build();
        }

        return new Retrofit.Builder()
                .baseUrl(apiUrl)
                .client(client)
                .addConverterFactory(GsonConverterFactory.create())
                .build();
    }
}